before_code.lib/libc/iconv/citrus_none.c::_citrus_NO:
static int
_citrus_NONE_stdenc_cstomb(struct _citrus_stdenc * __restrict ce __unused,
    char *s, size_t n, _csid_t csid, _index_t idx, void *ps __unused,
    size_t *nresult, struct iconv_hooks *hooks __unused)
{

	if (csid == _CITRUS_CSID_INVALID) {
		*nresult = 0;
		return (0);
	}
	if (csid != 0)
		return (EILSEQ);

	if ((idx & 0x000000FF) == idx) {
		if (n < 1) {
			*nresult = (size_t)-1;
			return (E2BIG);
		}
		*s = (char)idx;
		*nresult = 1;
	} else if ((idx & 0x0000FFFF) == idx) {
		if (n < 2) {
			*nresult = (size_t)-1;
			return (E2BIG);
		}
		s[0] = (char)idx;
		/* XXX: might be endian dependent */
		s[1] = (char)(idx >> 8);
		*nresult = 2;
	} else if ((idx & 0x00FFFFFF) == idx) {
		if (n < 3) {
			*nresult = (size_t)-1;
			return (E2BIG);
		}
		s[0] = (char)idx;
		/* XXX: might be endian dependent */
		s[1] = (char)(idx >> 8);
		s[2] = (char)(idx >> 16);
		*nresult = 3;
	} else {
		if (n < 3) {
			*nresult = (size_t)-1;
			return (E2BIG);
		}
		s[0] = (char)idx;
		/* XXX: might be endian dependent */
		s[1] = (char)(idx >> 8);
		s[2] = (char)(idx >> 16);
		s[3] = (char)(idx >> 24);
		*nresult = 4;
	}

	return (0);
}

